import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CdkAccordionItem } from '@angular/cdk/accordion';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCaretDown } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbAccordionComponent } from './accordion.component';
import {
  accordionContentVariants,
  accordionItemVariants,
  accordionTriggerVariants,
} from './accordion.variants';

@Component({
  selector: 'hb-accordion-item',
  hostDirectives: [CdkAccordionItem],
  imports: [NgIcon],
  template: `
    <button
      type="button"
      data-slot="accordion-trigger"
      [id]="'trigger-' + cdkItem.id"
      [attr.aria-controls]="'region-' + cdkItem.id"
      [attr.aria-expanded]="expanded()"
      [disabled]="hbDisabled()"
      [class]="triggerClasses"
      (click)="onTriggerClick()"
    >
      {{ hbTitle() }}
      <ng-icon name="phosphorCaretDown" [class.rotate-180]="expanded()" />
    </button>

    <div
      role="region"
      data-slot="accordion-content"
      [id]="'region-' + cdkItem.id"
      [attr.aria-labelledby]="'trigger-' + cdkItem.id"
      [attr.data-state]="state()"
      [inert]="!expanded()"
      [class]="contentClasses"
    >
      <div class="overflow-hidden">
        <div class="pt-0 pb-4">
          <ng-content />
        </div>
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  viewProviders: [provideIcons({ phosphorCaretDown })],
  host: {
    '[class]': 'itemClasses()',
    '[attr.data-slot]': "'accordion-item'",
    '[attr.data-state]': 'state()',
    '[attr.data-disabled]': "hbDisabled() ? '' : null",
  },
  exportAs: 'hbAccordionItem',
})
export class HbAccordionItemComponent {
  protected readonly cdkItem = inject(CdkAccordionItem);
  private readonly parent = inject(HbAccordionComponent);

  readonly hbTitle = input<string>('');
  readonly hbValue = input<string>('');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  private readonly _expanded = signal(false);
  readonly expanded = this._expanded.asReadonly();
  protected readonly state = computed(() => (this._expanded() ? 'open' : 'closed'));

  protected readonly itemClasses = computed(() =>
    cn(accordionItemVariants({ bordered: this.parent.hbBordered() }), this.class()),
  );
  protected readonly triggerClasses = cn(accordionTriggerVariants());
  protected readonly contentClasses = cn(accordionContentVariants());

  constructor() {
    this.cdkItem.expandedChange
      .pipe(takeUntilDestroyed())
      .subscribe((v) => this._expanded.set(v));

    effect(() => {
      this.cdkItem.disabled = this.hbDisabled();
    });
  }

  open(): void {
    this.cdkItem.open();
  }

  onTriggerClick(): void {
    if (this.expanded() && !this.parent.canClose()) return;
    this.cdkItem.toggle();
  }
}

import {
  afterNextRender,
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  effect,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { CDK_ACCORDION, CdkAccordion } from '@angular/cdk/accordion';

import { cn, type ClassValue } from '{{alias}}/utils';
import { accordionVariants, type HbAccordionBordered } from './accordion.variants';
import { HbAccordionItemComponent } from './accordion-item.component';

@Component({
  selector: 'hb-accordion',
  hostDirectives: [CdkAccordion],
  providers: [{ provide: CDK_ACCORDION, useExisting: CdkAccordion }],
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'accordion'",
  },
  exportAs: 'hbAccordion',
})
export class HbAccordionComponent {
  private readonly cdk = inject(CdkAccordion);

  readonly hbType = input<'single' | 'multiple'>('single');
  readonly hbCollapsible = input(true, { transform: booleanAttribute });
  readonly hbBordered = input<HbAccordionBordered>('divider');
  readonly hbDefaultValue = input<string | string[]>('');
  readonly class = input<ClassValue>('');

  readonly items = contentChildren(HbAccordionItemComponent);

  protected readonly classes = computed(() =>
    cn(accordionVariants({ bordered: this.hbBordered() }), this.class()),
  );

  constructor() {
    effect(() => {
      this.cdk.multi = this.hbType() === 'multiple';
    });

    afterNextRender(() => {
      const dv = this.hbDefaultValue();
      const values = Array.isArray(dv) ? dv : dv ? [dv] : [];
      for (const item of this.items()) {
        if (values.includes(item.hbValue())) item.open();
      }
    });
  }

  canClose(): boolean {
    if (this.hbCollapsible()) return true;
    const openCount = this.items().filter((i) => i.expanded()).length;
    return openCount > 1;
  }
}

import { HbAccordionComponent } from './accordion.component';
import { HbAccordionItemComponent } from './accordion-item.component';

export const HbAccordionImports = [HbAccordionComponent, HbAccordionItemComponent] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const accordionVariants = cva('block w-full', {
  variants: {
    bordered: {
      none: '',
      divider: '',
      card: 'rounded-lg border border-border overflow-hidden',
    },
  },
  defaultVariants: {
    bordered: 'divider',
  },
});

export const accordionItemVariants = cva(
  'block border-l-2 border-l-transparent pl-3 data-[state=open]:border-l-primary',
  {
    variants: {
      bordered: {
        none: '',
        divider: 'border-b border-border last:border-b-0',
        card: 'border-b border-border last:border-b-0 pr-4',
      },
    },
    defaultVariants: {
      bordered: 'divider',
    },
  },
);

export const accordionTriggerVariants = cva(
  cn(
    'flex w-full flex-1 items-center justify-between gap-4 py-4 text-left text-sm font-medium',
    'text-foreground/85 outline-none transition-colors cursor-pointer rounded-md',
    'hover:text-foreground',
    'focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:border-ring',
    'disabled:pointer-events-none disabled:opacity-50',
    '[&>ng-icon]:size-4 [&>ng-icon]:shrink-0 [&>ng-icon]:text-muted-foreground',
    'hover:[&>ng-icon]:text-foreground [&>ng-icon]:transition-transform [&>ng-icon]:duration-200',
  ),
);

export const accordionContentVariants = cva(
  cn(
    'grid text-sm text-muted-foreground transition-all duration-200',
    'data-[state=closed]:grid-rows-[0fr] data-[state=open]:grid-rows-[1fr]',
    'data-[state=closed]:opacity-0 data-[state=open]:opacity-100',
  ),
);

export type HbAccordionBordered = NonNullable<
  VariantProps<typeof accordionVariants>['bordered']
>;

export * from './accordion.component';
export * from './accordion-item.component';
export * from './accordion.variants';
export * from './accordion.imports';
